:root {
  --bg: #0A0A0A;
  --card: #141414;
  --border: #222;
  --text: #E0E0E0;
  --sub: #888;
}

body {
  background: var(--bg);
  color: var(--text);
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  padding: 20px;
}

#dashboard-container {
  max-width: 1200px;
  margin: 0 auto;
}

.header {
  display: flex;
  justify-content: space-between;
  align-items: flex-end;
  margin-bottom: 30px;
  border-bottom: 1px solid var(--border);
  padding-bottom: 20px;
}

.header h1 {
  margin: 8px 0;
  font-size: 26px;
  font-weight: 800;
  letter-spacing: -0.5px;
}

.badge {
  background: #4DA8DA;
  color: black;
  padding: 4px 8px;
  border-radius: 4px;
  font-size: 10px;
  font-weight: 900;
}

.subtext {
  color: var(--sub);
  font-size: 14px;
  margin: 0;
}

.main-val {
  font-size: 32px;
  font-weight: 900;
  text-align: right;
}

.kpi-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 16px;
  margin-bottom: 30px;
}

.kpi-card {
  background: var(--card);
  border: 1px solid var(--border);
  padding: 16px;
  border-radius: 12px;
}

.kpi-card .label {
  font-size: 10px;
  font-weight: 700;
  color: var(--sub);
  margin-bottom: 10px;
  text-transform: uppercase;
}

.kpi-card .value {
  font-size: 20px;
  font-weight: 800;
  margin-bottom: 5px;
}

.kpi-card .footer {
  font-size: 11px;
  color: #555;
}

.main-content {
  display: grid;
  grid-template-columns: 280px 1fr;
  gap: 24px;
  margin-bottom: 30px;
}

.side-panel {
  background: var(--card);
  border: 1px solid var(--border);
  padding: 20px;
  border-radius: 12px;
}

.chart-area {
  background: var(--card);
  border: 1px solid var(--border);
  padding: 20px;
  border-radius: 12px;
  min-height: 250px;
}

.section-title {
  font-size: 12px;
  font-weight: 800;
  color: #4DA8DA;
  text-transform: uppercase;
  margin-bottom: 15px;
}

.stats-list {
  list-style: none;
  padding: 0;
  margin: 0;
}

.stats-list li {
  display: flex;
  justify-content: space-between;
  padding: 12px 0;
  border-bottom: 1px solid #1A1A1A;
  font-size: 13px;
}

.pos {
  color: #30D158;
}

.neg {
  color: #FF453A;
}

.tables-container {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 24px;
}

.table-box {
  background: var(--card);
  border: 1px solid var(--border);
  padding: 20px;
  border-radius: 12px;
}

table {
  width: 100%;
  border-collapse: collapse;
  font-size: 12px;
}

th {
  text-align: left;
  color: var(--sub);
  padding-bottom: 10px;
  border-bottom: 1px solid #333;
}

td {
  padding: 10px 0;
  border-bottom: 1px solid #1A1A1A;
}

