let app;
let chart;
appsmith.onReady(() => {
  // 1. Initialize Vue with the model
  app = new Vue({
    el: '#app',
    data: {
      model: appsmith.model
    }
  });

  // 2. Initial Chart Render
  renderChart(appsmith.model.analytics.trend);
});

// Update Vue when model changes
appsmith.onModelChange(newModel => {
  if (app) app.model = newModel;
  if (chart && newModel.analytics.trend) {
    chart.data.labels = newModel.analytics.trend.map(d => d.month);
    chart.data.datasets[0].data = newModel.analytics.trend.map(d => d.qty);
    chart.update();
  }
});
function renderChart(trendData) {
  const ctx = document.getElementById('trendChart').getContext('2d');
  chart = new Chart(ctx, {
    type: 'line',
    data: {
      labels: (trendData || []).map(d => d.month),
      datasets: [{
        data: (trendData || []).map(d => d.qty),
        borderColor: '#4DA8DA',
        backgroundColor: 'rgba(77, 168, 218, 0.1)',
        fill: true,
        tension: 0.4
      }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: {
        legend: {
          display: false
        }
      },
      scales: {
        y: {
          grid: {
            color: '#1A1A1A'
          },
          ticks: {
            color: '#666'
          }
        },
        x: {
          grid: {
            display: false
          },
          ticks: {
            color: '#666'
          }
        }
      }
    }
  });
}

